"""
MKT Original Commentary — Exodus chapters 25–27
Run: python3 scripts/zc-original-exodus-25-27-fill.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json
- data/translation/notes/exodus.json

Key decisions in this range:
- kapporet (H3727) rendered 'atonement cover' not 'mercy seat' — retains the kapar/atonement root visible
- tabnit (H8403) rendered 'pattern/blueprint' — the heavenly archetype principle (Heb 8:5) grounds all design
- parochet (H6532) is the dividing veil, not merely a curtain — its tearing at the crucifixion (Matt 27:51) is the NT fulfillment
- mishkan from shakan (to dwell/tabernacle) — the same root John uses theologically in John 1:14
- katit (H3795) = beaten/crushed olive oil — Gethsemane (gat-shemen = olive press) is the lexical echo
- adanim (H134) = silver sockets — not derived from adon but their function as the foundation of the holy structure
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
"25": {
"1": "<p>Standard commission formula: <strong>vayedaber YHWH el-Moshe lemor</strong> (<em>vay-yeh-dah-BER YHWH el-Mo-SHEH le-MOR</em>): 'And YHWH spoke to Moses, saying.' The Sinai legislation now pivots from the Decalogue and mishpatim (civil law, chs. 21-23) to the construction of the divine dwelling — miqdash and mishkan — as the covenant's physical expression.</p>",
"2": "<p><strong>terumah</strong> (<em>teh-roo-MAH</em>): 'contribution/heave offering.' H8641, from <em>rum</em> (to lift/raise — H7311). The offering is lifted toward God. Critical qualifier: <strong>nediv libbo</strong> (<em>neh-DEEV lib-BO</em>), 'whose heart moves him willingly' — H5068 from <em>nadav</em> (to give freely/volunteer). The tabernacle is built by freewill generosity, not conscription. Same root as the <em>nedivim</em> (noble/generous ones) throughout the Psalms. Paul echoes this principle in 2 Cor 9:7.</p>",
"3": "<p>Materials in descending value: <strong>zahav, kesef, nechoshet</strong> (<em>zah-HAV, KEH-sef, neh-KHO-shet</em>): 'gold, silver, bronze.' These three metals map spatially onto the tabernacle zones — gold in the most holy place and holy place, silver as socket-foundations, bronze in the outer court. Sacred space is marked materially: proximity to divine presence corresponds to purity of metal.</p>",
"4": "<p><strong>tekhelet</strong> (<em>teh-kheh-LET</em>): 'blue' (H8504, possibly from Murex snail dye — same source as the tzitzit blue thread, Num 15:38). <strong>argaman</strong> (<em>ar-gah-MAN</em>): 'purple' (H713, a prestige color in the ancient world, associated with royalty). <strong>tola'at shani</strong> (<em>toh-lah-AT shah-NEE</em>): 'scarlet worm-dye' (H8438/H8144, from the kermes scale insect). <strong>shesh</strong> (<em>shesh</em>): 'fine linen' (H8336, Egyptian). These four materials are the signature of sacred space throughout the tabernacle, priestly garments, and the high priest's vestments — a visual theology of holiness.</p>",
"5": "<p><strong>ore tachash</strong> (<em>oh-ROT tah-KHASH</em>): 'tachash skins' (H8476 — the animal is unidentified; candidates include dugong, porpoise, or a now-extinct land animal). <strong>atzei shittim</strong> (<em>ah-TZEI shit-TEEM</em>): 'acacia wood' (H7848 H6086). Acacia is a desert-resistant hardwood — extremely dense, resistant to rot and insects. Its use for the ark, altar, and table is theologically significant: the incorruptible wood that bears the holy furnishings anticipates the incorruptible flesh that bears the divine presence (cf. Ps 16:10, Acts 2:27).</p>",
"6": "<p><strong>shemen hammishchah</strong> (<em>sheh-MEN ha-MISH-chah</em>): 'the anointing oil' (H8081 H4888, from <em>mashach</em> — to anoint, the root of <em>mashiach</em>/Messiah). <strong>qetoret hasamim</strong> (<em>qeh-TOH-ret ha-sam-MEEM</em>): 'incense of spices' (H7004 H1314). Both items define the priestly/cultic ministry: anointing consecrates, incense represents the ascending prayers of the people before God (cf. Rev 8:3-4).</p>",
"7": "<p><strong>avnei shoham</strong> (<em>av-NEI sho-HAM</em>): 'shoham stones' (H7718 — possibly onyx or a precious stone; identification uncertain). <strong>avnei milu'im</strong> (<em>av-NEI mih-loo-EEM</em>): 'setting/filling stones' (H4394, from <em>male</em> H4390 — to fill). The word for gem settings (<em>milu</em>) echoes the filling/fulfillment language of creation (Gen 1:28 <em>umilu</em>) — the sacred garments are filled/completed with precious stones.</p>",
"8": "<p><strong>miqdash</strong> (<em>mik-DASH</em>): 'sanctuary' (H4720, from <em>qadash</em> — to be holy/set apart). <strong>mishkan</strong> (<em>mish-KAN</em>): 'tabernacle/dwelling' (H4908, from <em>shakan</em> H7931 — to dwell/settle/tabernacle). The purpose statement — <em>veshakhanti betokham</em>, 'that I may dwell among them' — is one of the most theologically loaded sentences in the Torah. The mission of the tabernacle is divine indwelling in the midst of the people. John 1:14 employs the same Greek root (<em>eskenos</em> = tabernacled) to describe the Incarnation: the eternal Word pitched his tabernacle among us.</p>",
"9": "<p><strong>tabnit</strong> (<em>tab-NEET</em>): 'pattern/blueprint/model' (H8403, from <em>banah</em> — to build). The earthly tabernacle is a copy of a heavenly original — God shows Moses the <em>tabnit</em> on the mountain, and Israel must replicate it exactly. Hebrews 8:5 cites this verse explicitly: the Levitical priests serve a copy and shadow of the heavenly sanctuary. The principle runs through Ex 25-31: every dimension, material, and furnishing is revealed, not invented. The tabernacle is a human-built replica of the divine dwelling that always existed.</p>",
"10": "<p><strong>aron</strong> (<em>ah-RON</em>): 'ark/chest/box' (H727). The same word is used for Joseph's coffin in Gen 50:26 — the only two uses in the Pentateuch of <em>aron</em> for a chest. The ark contains the tablets of the covenant — it is the treasure chest of the divine word. Dimensions: 2.5 cubits long, 1.5 wide, 1.5 high. <strong>atzei shittim</strong> — acacia wood again — the incorruptible wood at the heart of the sanctuary.</p>",
"11": "<p><strong>zahav tahor</strong> (<em>zah-HAV tah-HOR</em>): 'pure gold' (H2091 H2889). The ark is overlaid with pure gold inside and out — total consecration, every surface. <strong>zar zahav</strong> (<em>zehr zah-HAV</em>): 'crown/molding of gold' (H2213), surrounding the top of the ark — a royal crown befitting the footstool of the King of the universe.</p>",
"12": "<p><strong>arba tabbaot zahav</strong> (<em>ar-BAH tab-ah-OT zah-HAV</em>): 'four gold rings' (H702 H2885 H2091). The rings are the interface between the holy ark and the carrying poles — the only means by which human hands can transport the divine presence without touching it directly. Placed at the four feet, or at the four lower corners, of the ark.</p>",
"13": "<p><strong>baddim</strong> (<em>bad-DEEM</em>): 'poles/staves' (H905, plural of <em>bad</em>). The root <em>bad</em> can mean separation, isolation, or the pole itself. The carrying poles of acacia wood overlaid with gold are the instruments by which the presence of God travels with the people. The <em>baddim</em> make the ark portable — YHWH is not bound to a fixed place but travels with his covenant community.</p>",
"14": "<p>The poles are inserted into the rings on the sides of the ark — the ark's carrying system. The instruction anticipates the wilderness journey: the divine presence must move with Israel through the desert. The danger of touching the ark directly is illustrated later in the narrative of Uzzah (2 Sam 6:6-7), where even well-intentioned contact without the prescribed mediation proves fatal — holiness requires mediation.</p>",
"15": "<p><strong>lo yasuru mimmenu</strong> (<em>lo yah-SOO-roo mim-ME-noo</em>): 'they shall not be removed from it.' The poles are permanently in place — the ark is always in a state of readiness for movement. This permanence of the carrying apparatus reflects the pilgrim nature of the divine dwelling: even when Israel is at rest, God's presence is ready to move. The command distinguishes the ark from other sacred furniture whose poles could be removed.</p>",
"16": "<p><strong>haedut</strong> (<em>hah-ay-DOOT</em>): 'the testimony/witness tablets' (H5715, from <em>ud</em> — to testify/repeat). The tablets of the Decalogue placed inside the ark are <em>haedut</em> — the divine testimony, the witness of covenant. This names the ark: <em>aron haedut</em> = ark of the testimony. The tablets inside the ark function as the covenant document at the heart of the divine dwelling, like a suzerainty treaty stored in the sanctuary.</p>",
"17": "<p><strong>kapporet</strong> (<em>kap-PO-ret</em>): 'atonement cover/mercy seat' (H3727, from <em>kapar</em> H3722 — to cover, to atone, to make propitiation). This is the most theologically concentrated piece of furniture in the tabernacle. On Yom Kippur (Lev 16), the high priest sprinkles the blood of the sin offering on the <em>kapporet</em> — the blood of atonement applied directly to the cover of the covenant tablets, between the cherubim, in the divine presence. The LXX renders it <em>hilasterion</em>, the same word Paul uses in Rom 3:25 for what God put forward in Christ as the place of atonement. Dimensions: 2.5 cubits × 1.5 cubits — exact match to the top of the ark.</p>",
"18": "<p><strong>shenei cheruvim zahav</strong> (<em>she-NEI kheh-roo-VEEM zah-HAV</em>): 'two gold cherubim.' <strong>mikshah</strong> (<em>mik-SHAH</em>): 'hammered/beaten work' (H4749, from <em>naqash</em>? or <em>kasha</em> = beaten into shape). The cherubim are not cast separately and mounted — they are beaten out of the same gold as the <em>kapporet</em>. Cherubim (H3742) are the guardians of sacred divine space throughout Scripture, from Eden (Gen 3:24) to the heavenly throne room (Ezek 1, Rev 4).</p>",
"19": "<p><strong>miqqetseh hakapporet</strong> (<em>mik-KET-zeh hah-kap-PO-ret</em>): 'from the end of the atonement cover.' The two cherubim emerge from the two ends of the <em>kapporet</em> — they are one piece with it. The divine meeting place is flanked by the guardians of divine holiness. The unity of material (one piece of hammered gold) signals that access to the divine presence is inseparable from the atoning mediation of the <em>kapporet</em>.</p>",
"20": "<p><strong>porsim kanfeihem</strong> (<em>po-REEM kan-fei-HEM</em>): 'spreading their wings' (H6566/H3671, <em>paras/kanaph</em>). The wings of the cherubim shelter or overshadow the <em>kapporet</em> from above. <strong>upeneihem ish el achiv</strong>: 'their faces toward one another' — facing each other, looking down toward the <em>kapporet</em>. This posture defines the divine throne: YHWH is enthroned above the cherubim (1 Sam 4:4, Ps 80:1), in the space between their overshadowing wings.</p>",
"21": "<p>The <em>kapporet</em> is placed on top of the ark, with the <em>edut</em> (testimony tablets) inside. The sequence — covenant document inside, atonement cover on top — is architecturally theological: the covenant law is covered by (and accessible only through) the atonement of divine mercy. The tablets demand; the <em>kapporet</em> answers.</p>",
"22": "<p><strong>veno'adti lekha sham</strong> (<em>ve-no-AD-ti lekh-AH SHAM</em>): 'and I will meet with you there' (H3259, from <em>ya'ad</em> — to appoint, to meet at an appointed time). The word for meeting (<em>mo'ed</em>) comes from this root — the Tent of Meeting (<em>ohel mo'ed</em>) is the place of divine appointments with Israel. <strong>mi'bayn shnei hakeruvim</strong>: 'from between the two cherubim' — the precise location of YHWH's speech: the mercy seat between the cherubim is the interface between heaven and earth, the place where divine communication enters human history.</p>",
"23": "<p><strong>shulhan</strong> (<em>shool-KHAN</em>): 'table' (H7979). The table for the bread of the presence stands in the holy place outside the veil. Acacia wood, overlaid with gold. The table is the second piece of holy furniture — after the ark, the table. Israel's covenant with YHWH is structured as a meal before him.</p>",
"24": "<p>Pure gold overlay for the table; <strong>zar zahav</strong> (crown/molding of gold) surrounding it — matching the ark's crown. The gold crown or rim may have served a practical function (keeping items in place) while symbolically marking the table as royal furnishing in the divine throne room.</p>",
"25": "<p><strong>misgereth</strong> (<em>mis-GEH-ret</em>): 'border/frame/rim' (H4526, from <em>sagar</em> — to close/shut H5462). A handsbreadth-wide border surrounding the table. <strong>zar zahav</strong> again — the crown molding appears on both the ark and the table, marking them as the two central furnishings of the divine dwelling (covenant and provision).</p>",
"26": "<p>Four gold rings for the table, one at each corner — the same carrying system as the ark. The rings placed at the four feet enable the table to travel with Israel. The table of the divine presence is not a fixed monument but a traveling provision for the pilgrim people.</p>",
"27": "<p>The rings are close to the <em>misgereth</em> (border/rim) to hold the carrying poles. Precise engineering — the rings must be positioned to keep the poles level with the table surface during transport, preventing the sacred bread and vessels from sliding.</p>",
"28": "<p><strong>baddei shittim</strong> (<em>bad-DEI shit-TEEM</em>): 'acacia poles' — same material and principle as the ark's poles. The table travels on the same wood as the ark: acacia (incorruptible desert hardwood) overlaid with gold. The table is as portable as the covenant — divine provision travels wherever the covenant people travel.</p>",
"29": "<p><strong>qe'arotav</strong> (<em>ke-ah-ro-TAV</em>): 'its plates' (H7086); <strong>kappotav</strong> (<em>kap-po-TAV</em>): 'its pans/dishes' (H3709 — same word as palms of hands, the cupped shape); <strong>qeshavot</strong> (<em>ke-sha-VOT</em>): 'its pitchers/flagons' (H7184); <strong>menaqiyyot</strong> (<em>me-nah-ki-YOT</em>): 'its bowls' (H4518). All for the <strong>nesekh</strong> (<em>NEH-sekh</em>): 'libation/drink offering' (H5262). The table is fully equipped for a sacred meal service — vessels for bread, wine, and offering. Divine hospitality is not sparse.</p>",
"30": "<p><strong>lehem hapanim</strong> (<em>LEH-khem hah-pah-NEEM</em>): 'bread of the face/presence' (H3899 H6440). Literally: face-bread, or presence-bread — twelve loaves set before the face of YHWH perpetually (<em>tamid</em>). The twelve loaves represent the twelve tribes in constant presentation before God. In 1 Sam 21:1-6 David eats the sacred showbread in extremity, and Jesus appeals to this incident to teach that the sabbath/cultic law serves human need (Matt 12:3-4). The lehem hapanim anticipates the eschatological banquet where the redeemed eat at the divine table.</p>",
"31": "<p><strong>menorah</strong> (<em>me-no-RAH</em>): 'lampstand' (H4501, from root <em>nwr/nyr</em> — light, lamp H5216). <strong>zahav tahor</strong> — pure gold. <strong>mikshah</strong>: hammered out of one piece — not assembled from parts but beaten into its branching form from a single talent of pure gold. The menorah is the light of the divine house. Zechariah 4 interprets the menorah as the light of YHWH's Spirit (<em>not by might nor by power</em>). John 8:12 applies the light-language to Jesus as the light of the world.</p>",
"32": "<p><strong>shisha qanim</strong> (<em>shee-SHA kah-NEEM</em>): 'six branches' (H8337 H7070) — three from each side of the central shaft. <strong>yerech</strong> (<em>YEH-rekh</em>): 'thigh/central shaft' (H3409 — the same word used for the thigh/base of the body). The lamp's central pillar is described with the human body word for the thigh — architectural anthropomorphism, the living lamp with a spine and branches.</p>",
"33": "<p><strong>gevi'im meshukadim</strong> (<em>ge-vi-EEM me-shoo-KAH-deem</em>): 'almond-shaped cups' (H1375 H8247). The menorah's ornamental cups are shaped like almond blossoms — the <em>shaqed</em> (almond tree H8247) is the first tree to blossom in Israel (January), its name from <em>shaqad</em> = to wake/be alert/watch. Aaron's rod that budded was an almond branch (Num 17:8). <strong>kaftor</strong> (<em>kaf-TOR</em>): 'knob/capital' (H3730); <strong>perach</strong> (<em>PEH-rakh</em>): 'flower/blossom' (H6525). The lamp is adorned with imagery of new life, watchfulness, and blossoming.</p>",
"34": "<p>The central shaft has four cups with knobs and blossoms — more ornamentation than the six branches (which have three each). The central trunk of the menorah is the most elaborate — the source from which the branches radiate. This structural emphasis on the central shaft anticipates the menorah's interpretation in Zechariah 4 and John 15 (the vine and branches).</p>",
"35": "<p>The structural specification: a knob beneath each pair of branches — there are three pairs of branches, so three knobs on the central shaft where branches emerge. The total structure has a mathematical harmony: 7 lamps, 6 branches, specific cup/knob/blossom counts at each joint. This precision is not mere aesthetics but reflects the orderliness of creation and divine wisdom.</p>",
"36": "<p><strong>mikshah echad zahav tahor</strong> (<em>mik-SHAH eh-KHAD zah-HAV tah-HOR</em>): 'one hammered piece of pure gold.' The entire menorah — shaft, branches, cups, knobs, blossoms — is beaten from one talent of gold. No joints, no assembly, no seams. This unity of material reflects the oneness of the divine light that illuminates Israel. The menorah cannot be disassembled into parts; its light is whole and indivisible.</p>",
"37": "<p><strong>shiv'at neroteyha</strong> (<em>shiv-AT ne-ro-TEI-hah</em>): 'its seven lamps' (H7651 H5216). Seven is the number of covenantal completeness throughout Scripture. The seven lamps are to be arranged to illuminate the space in front of the lampstand — <strong>el ever paneyha</strong>: toward its face. The menorah faces the table of the bread of the presence — the light illuminates the divine provision, and both face the entrance, available to approach.</p>",
"38": "<p><strong>melqachayyim</strong> (<em>mel-kah-KHI-yim</em>): 'tongs/snuffers' (H4457, from <em>laqach</em> — to take); <strong>machtot</strong> (<em>makh-TOT</em>): 'trays/fire pans' (H4289). All pure gold. The tongs for trimming the wicks and the trays for carrying the ash are as sacred as the lamp itself — every element of worship is consecrated. Even the maintenance tools bear the mark of holiness.</p>",
"39": "<p><strong>kikar zahav tahor</strong> (<em>ki-KAR zah-HAV tah-HOR</em>): 'a talent of pure gold' (H3603 H2091 H2889). A <em>kikar</em> is approximately 34 kg / 75 lbs. The entire menorah, including all its vessels, is hammered from one talent of pure gold. This is one of the largest single-material sacred objects — the light of the divine house is costly, the most expensive furnishing in terms of raw gold weight.</p>",
"40": "<p><strong>ure'eh va'aseh betavnitam</strong> (<em>oo-re-EH va-ah-SEH be-tav-ni-TAM</em>): 'and see and make according to their pattern' (H7200/H6213/H8403). The closing command echoes v.9 — both the tabernacle and the menorah are built from the <em>tabnit</em> revealed on the mountain. <strong>asher-attah mar'eh bahar</strong>: 'which you are shown on the mountain.' Heb 8:5 and 9:23 apply this principle broadly: the entire Levitical system is a copy (<em>hupodeigma</em>) and shadow (<em>skia</em>) of the heavenly realities. The earthly tabernacle does not merely house God — it images the heavenly sanctuary where Christ now ministers.</p>"
},
"26": {
"1": "<p><strong>ha-mishkan</strong> (<em>hah-mish-KAN</em>): 'the tabernacle' — now the structure itself is described. <strong>yeriot</strong> (<em>ye-ri-OT</em>): 'curtains/sheets' (H3407). <strong>shesh moshzar</strong> (<em>shesh mo-SHAR</em>): 'twisted fine linen' (H8336 H7806 — braided/twisted). <strong>ma'aseh choshev</strong> (<em>mah-ah-SEH kho-SHEV</em>): 'work of a skilled craftsman/designer' (H4639 H2803 — from <em>chashav</em> = to think/devise/plan/weave). The highest grade of weaving — the curtains that form the inner skin of the tabernacle are the product of intentional design, skilled execution, and artistic thought. The same root <em>chashav</em> means to think or reckon — the tabernacle is a thought made fabric.</p>",
"2": "<p>The dimensions of each inner curtain: 28 cubits long and 4 cubits wide — approximately 14m × 2m. All ten curtains identical in size: <strong>mida achat lechol hayeriot</strong> — one measure for all the curtains. The uniformity signals that there is no hierarchy among the curtains themselves; only their assembly into joined sets creates structure.</p>",
"3": "<p>Five curtains joined to one another, and five joined to one another — two sets of five. The joining (<em>chabar</em> H2266 — to unite/couple) creates two large panels that are then clasped together to form the whole tabernacle ceiling. The number five appears repeatedly in the tabernacle — five curtains, five pillars at the entrance — and may echo the Pentateuch structure or the five fingers of the priestly hand.</p>",
"4": "<p><strong>lulot tekhelet</strong> (<em>loo-LOT te-kheh-LET</em>): 'loops of blue' (H3924 H8504). The loops are made along the edge of the last curtain in each set — fifty loops on each edge, positioned to align precisely with the loops on the opposite set. The blue (<em>tekhelet</em>) of the loops marks this joining edge as sacred — the same blue as the priests' garments and the tzitzit thread.</p>",
"5": "<p><strong>chamishim lulot</strong> (<em>kha-mish-EEM loo-LOT</em>): 'fifty loops' on each set — the total join has 50 pairs of loops. Fifty is significant: the Jubilee year is the 50th year (Lev 25:10), and the Feast of Weeks (Shavuot/Pentecost) is the 50th day after Passover. The tabernacle's internal structure carries the number of divine release and covenant renewal.</p>",
"6": "<p><strong>klasei zahav</strong> (<em>klah-SEI zah-HAV</em>): 'golden clasps' (H7165 H2091). Fifty gold clasps join the two halves of the inner tabernacle into one: <strong>vehayah hamishkan echad</strong> — 'and the tabernacle shall be one.' The architectural unity of the sanctuary reflects the oneness of its God. Fifty gold clasps, 50 bronze clasps for the outer covering — the same number unifies the sacred dwelling at both layers.</p>",
"7": "<p><strong>yeriot izim</strong> (<em>ye-ri-OT iz-ZEEM</em>): 'curtains of goat hair' (H3407 H5795). The second layer of covering — eleven curtains of goat hair over the inner linen curtains. Goat hair was used for tent fabric throughout the ancient Near East — waterproof and durable. The outer layers protect the inner; the sacred linen curtains with cherubim are never exposed to the elements.</p>",
"8": "<p>The goat hair curtains are slightly larger than the inner linen ones: 30 cubits long (vs. 28) and 4 cubits wide. The extra length allows for overhang. Eleven curtains vs. the inner ten — the outer covering is more extensive, wrapping further around the sacred structure. The slight excess is architectural wisdom for desert conditions.</p>",
"9": "<p>The sixth curtain is to be folded double at the front of the tent — the doubled curtain creates extra thickness at the entrance, where wear and exposure are greatest. The arrangement reveals practical engineering within the sacred commission: durability serves holiness. The doubled front also creates a visual marker of the entrance.</p>",
"10": "<p>Fifty loops on the edge of the last outer curtain, aligned to match the inner curtains' loops. The same 50-loop structure — the outer goat hair covering mirrors the inner linen covering in its joining system. The tabernacle is built by correspondence: inner and outer, above and below, holy and most holy are all parallel structures.</p>",
"11": "<p><strong>klasei nechoshet</strong> (<em>klah-SEI ne-KHO-shet</em>): 'bronze clasps' (H7165 H5178). Bronze for the outer goat hair covering, gold for the inner linen curtains — the decreasing value of metals as one moves outward reflects the graduated holiness of the tabernacle zones: gold (most holy/holy places), silver (sockets/bases), bronze (outer court). Even the clasps encode the theology of access.</p>",
"12": "<p>The half-curtain surplus from the odd eleventh curtain hangs down over the back of the tabernacle. Nothing is wasted in the divine design — the extra curtain creates additional back coverage. The instruction reveals that the outer covering extends beyond the inner curtains on all sides, protecting the sacred structure completely.</p>",
"13": "<p>A cubit of extra length hangs down on each side of the tabernacle. The outer covering is longer than the inner by two cubits total — one cubit of overhang per side. The inner curtains are fully enclosed within the outer covering. This architectural detail reinforces the principle: holiness is surrounded, protected, and approached only through layers of mediation.</p>",
"14": "<p><strong>ore eilim meaddamim</strong> (<em>oh-ROT ay-LEEM me-ad-dah-MEEM</em>): 'rams' skins dyed red' (H5785 H352 H119, from <em>adam</em> = red/ruddy — same root as <em>adam</em>/human and <em>edom</em>/red). <strong>ore tachashim</strong>: tachash skins (H8476). The two outermost layers are utilitarian coverings — water-resistant animal skins. The innermost layer is gold and cherubim; the outermost is animal hide. The tabernacle is wrapped in mortality to enclose the divine presence — a structural parable of incarnation.</p>",
"15": "<p><strong>kerashim</strong> (<em>ke-rah-SHEEM</em>): 'planks/boards/frames' (H7175, singular <em>keresh</em>). The upright wooden framework of the tabernacle — 48 boards total forming the three solid walls. <strong>atzei shittim omedim</strong>: 'standing/upright acacia planks.' <em>Omedim</em> from <em>amad</em> (to stand H5975) — the same word for those who stand in divine service. The planks stand upright before YHWH.</p>",
"16": "<p>Each board: <strong>eser ammot orech haqqeresh</strong> — ten cubits long (ca. 4.5m), and one and a half cubits wide (<em>amah va-chatzi</em>). The height of the boards (ten cubits) determines the interior height of the tabernacle — ten cubits of standing room for the worship of the Holy One. Ten is the number of the Decalogue; the house of the commandments stands ten cubits tall.</p>",
"17": "<p><strong>shetei yadot laqqeresh echad</strong> (<em>she-TEI yah-DOT la-KE-resh eh-KHAD</em>): 'two tenons/hands for each board' (H3027). <strong>Yadot</strong> is the plural of <em>yad</em> — hand. The mortise-tenon joints by which each board is inserted into its silver base are called hands. The boards are planted into the earth by their hands — anthropomorphic building language. Every board has two hands reaching down into the silver sockets that hold it. The architecture uses human body vocabulary: the tabernacle has hands and feet.</p>",
"18": "<p>The south side (<em>negev</em> H5045 — same word as the Negev desert) receives twenty boards. The full south wall. <strong>lemiphat negev teymana</strong>: 'for the south side, southward' — the southern exposure of the desert tabernacle, facing the prevailing winds and maximum sun. Twenty boards for the longest walls.</p>",
"19": "<p><strong>arbaim adnei kesef</strong> (<em>ar-bah-EEM ad-NEI KEH-sef</em>): 'forty silver sockets/bases' (H134 H3701). Two sockets per board, under each of the two tenons. The silver sockets are the foundation of the entire tabernacle structure — the boards are not set into the ground but into cast silver. The number of silver sockets (96 total for the walls plus 4 for the veil = 100) connects to the 100 silver talents contributed as the silver redemption money counted in Ex 38:25-28. The foundation of the tabernacle literally rests on the ransom silver of the people.</p>",
"20": "<p>The north side: twenty boards — matching the south side exactly. The tabernacle is symmetrical: north and south walls identical in board count, dimensions, and silver socket foundations. This bilateral symmetry reflects the orderliness of the divine dwelling — nothing is haphazard, everything corresponds.</p>",
"21": "<p>Forty silver sockets for the north side — two per board, twenty boards. The total for the two long walls: 80 silver sockets, foundation of 40 boards. The silver foundation runs the full length of both long walls, unbroken. The most holy place rests on silver as surely as the outer court does — the entire sanctuary has a unified silver foundation.</p>",
"22": "<p><strong>ulirkete ha-mishkan yamah</strong> (<em>oo-lir-ke-TEI hah-mish-KAN yah-MAH</em>): 'and for the rear of the tabernacle westward' (<em>yam</em> = sea, the west — Israel orients by the Mediterranean Sea to the west). The west end gets six boards — the shorter back wall. The tabernacle faces east (entrance to the east, most holy place to the west) — oriented toward the rising sun while the divine presence dwells in the west.</p>",
"23": "<p><strong>ulirkete ha-mishkan shetei qerashot</strong>: 'and for the corners of the tabernacle at the rear — two corner boards.' <strong>miqqtso'ot</strong>: corner boards (H4742, from <em>qatsa</em> = corner/edge). The corner boards are a structural challenge — they must join two perpendicular walls while maintaining the uniform dimensions. The instruction that follows (v.24) explains how they are doubled and joined at the top.</p>",
"24": "<p><strong>veyihyu toa-mim mitachat veyachdav yihyu el rosho</strong>: 'they shall be twin from below, and together they shall be at its top, to the one ring.' The corner boards are doubled — each corner has two boards joined together, creating a structural column at each rear corner. They are joined at the top by one ring, binding the two corner boards into a single unit. This engineering solution for the corners reflects sophisticated desert carpentry within the divinely revealed design.</p>",
"25": "<p>Eight boards for the west end (six boards + two doubled corner boards = eight total positions). Sixteen silver sockets — two per board. <strong>shisha qereshim velirkat</strong>: six boards for the back, plus two corner boards = eight total. The west wall closes the tabernacle, sealing the most holy place at the rear.</p>",
"26": "<p><strong>berikhim atzei shittim</strong> (<em>be-ri-KHEEM ah-TZEI shit-TEEM</em>): 'crossbars of acacia wood' (H1280 H6086 H7848). From <em>barach</em> — to flee through, to pass through (H1272). The horizontal crossbars run through rings in the boards, binding the vertical boards into a unified wall. Five bars for each side — five bars hold the south wall, five the north wall, five the west wall.</p>",
"27": "<p>Five crossbars for the north wall, five for the west wall — the same structural system on all three sides. The crossbars ensure that the individual boards cannot topple or separate during the desert march and reassembly. They pass through gold rings in the boards, becoming part of the gold-overlay system — even the structural engineering is consecrated.</p>",
"28": "<p><strong>haberiach hatikkon betokh haqqereshim</strong> (<em>hah-be-ri-AKH hah-ti-KHON be-TOKH hah-keh-rah-SHEEM</em>): 'the middle crossbar in the middle of the boards' — <em>tikkoni</em> = middle/central (H8484). The central bar runs the full length of the wall from end to end. This central spine of the tabernacle — running through the middle of all the boards on each wall — is the structural backbone of the divine house. The middle bar is hidden within the boards, invisible once installed, like the spine within the body.</p>",
"29": "<p>The boards are overlaid with gold (<em>tetzapeh zahav</em>); gold rings hold the crossbars; the crossbars themselves are overlaid with gold. The entire wooden structure — boards and bars alike — is encased in gold. The wood is the structural support; the gold is the sacred surface. The incorruptible acacia provides the skeleton; the pure gold provides the glory. Nothing of the wooden structure is visible inside the tabernacle — only gold.</p>",
"30": "<p><strong>kahaqem et ha-mishkan kemishpato</strong> (<em>kah-HA-kem et hah-mish-KAN ke-mish-PA-to</em>): 'you shall set up the tabernacle according to its ordinance/manner' — <em>mishpat</em> (H4941, ordinance, right manner) here means the proper procedure/design revealed to Moses. The third reference to the revealed pattern (cf. vv. 9, 40 in ch.25) — the assembly of the tabernacle is not improvisational. There is a right way, a divinely ordained order, for establishing the sacred dwelling.</p>",
"31": "<p><strong>parochet</strong> (<em>pah-RO-khet</em>): 'veil/curtain' (H6532, perhaps from <em>parach</em> = to separate/divide or from Akkadian <em>baraku</em>). The inner veil is the most theologically significant piece of fabric in the tabernacle. Same materials as the inner curtains (tekhelet/argaman/shani/shesh), with cherubim woven in by the most skilled craftsman (<em>choshev</em>). This veil separates the holy place from the holy of holies — the barrier between human worship and the divine throne. It is this veil that tears from top to bottom at the crucifixion of Jesus (Matt 27:51; Mark 15:38), the torn flesh of Christ opening the way into the divine presence (Heb 10:19-20): a new and living way through the veil.</p>",
"32": "<p>Four acacia pillars overlaid with gold, with gold hooks (<em>vavihem zahav</em>), set in four silver sockets (<em>arba adnei kesef</em>). The parochet hangs from the gold hooks on these four pillars. The pillars stand between the holy place and the most holy — the threshold of access. Four pillars: four is the number of the earth's corners, of completeness in the material realm. The silver bases again: the sacred structure rests on silver redemption.</p>",
"33": "<p><strong>vehivdilah haparochet lachem bayn haqdosh uvayn qodesh haqdoshim</strong>: 'and the veil shall divide for you between the holy place and the holy of holies.' The architectural division of the tabernacle is explicit: the parochet creates two zones — haqdosh (the holy place, outer room) and qodesh haqdoshim (the holy of holies, inner room). The veil is not merely decoration but a theological boundary: the most holy place is inaccessible to all but the high priest, once a year, on Yom Kippur. This spatial theology of graduated access is dissolved in Christ (Heb 9:8, 12).</p>",
"34": "<p>The <em>kapporet</em> (atonement cover) is placed on the <em>aron haedut</em> (ark of the testimony) in the <em>qodesh haqdoshim</em>. The sequence: ark inside, kapporet on top, parochet surrounding — the most holy objects are the most enclosed. Three zones of access (outer court → holy place → holy of holies) correspond to three levels of approach: Israel, priests, high priest. The high priest alone enters the innermost room, only on one day of the year, only with blood.</p>",
"35": "<p>The table of the bread of the presence is placed outside the veil on the north side; the menorah is placed opposite on the south side. These two furnishings face each other across the holy place, both outside the parochet — the bread of divine provision and the light of divine presence flanking the approach to the veil. All three furnishings of the holy place (altar of incense, table, menorah) are positioned with precise intentionality.</p>",
"36": "<p><strong>masak</strong> (<em>mah-SAK</em>): 'screen/curtain' (H4539, from <em>nasak</em> — to weave?). The screen for the entrance to the tent is woven in the same four colors as the parochet but without cherubim — the entrance has the colors of holiness but lacks the angelic guardians that mark the boundary of the most holy. The masak is an invitation; the parochet is a warning. Entry into the holy place is open to the priests; entry through the parochet is reserved for the high priest alone.</p>",
"37": "<p>Five acacia pillars overlaid with gold, with gold hooks, for the entrance screen — but five bronze sockets (<em>adnei nechoshet</em>), not silver. The change from silver to bronze at the entrance marks the threshold between the holy place system and the outer court system: silver belongs to the inner sanctuary, bronze to the outer court. The entrance pillars stand at the exact boundary where the two material systems meet — a precise material theology of spatial holiness.</p>"
},
"27": {
"1": "<p><strong>mizbeach</strong> (<em>miz-BE-akh</em>): 'altar' (H4196, from <em>zabach</em> H2076 — to slaughter/sacrifice). The altar is named from the act it enables: the slaughter of sacrifice. It is 5 cubits × 5 cubits × 3 cubits high — square, with equal sides. The square shape may symbolize completeness and equal access from all four directions. The altar of burnt offering stands at the entrance to the tabernacle courtyard — the first thing encountered when approaching the divine dwelling. There is no access to the sanctuary without first passing the altar of sacrifice.</p>",
"2": "<p><strong>qarayyim</strong> (<em>kar-NAI-yim</em>): 'horns' (H7161, from <em>qeren</em> — horn, also power/authority H7161). The four horns project from the four corners of the altar — one piece with the altar, not added on. The horns are where the blood of the sin offering is applied (Lev 4:7, 18), and where fugitives clung for asylum (1 Kings 1:50; 2:28). The horn is simultaneously the place of atonement and the place of refuge — power channeled into protection. <strong>nechoshet</strong> overlay: bronze, the material of the outer court.</p>",
"3": "<p>The five altar utensils: <strong>sirotav</strong> (pots/buckets for removing ash H5518); <strong>ya'av</strong> (shovels H3257); <strong>mizraqotav</strong> (sprinkling bowls H4219 — for receiving and dashing the blood against the altar sides); <strong>mizlegotav</strong> (flesh hooks H4207 — for handling the sacrificial portions); <strong>machtotav</strong> (fire pans H4289 — for carrying coals). Every aspect of sacrificial service has its designated tool. The whole cultic system is equipped and ordered — nothing left to improvisation at the place of sacrifice.</p>",
"4": "<p><strong>mikbar nechoshet</strong> (<em>mik-BAR ne-KHO-shet</em>): 'bronze grating/lattice' (H4345 H5178). A bronze network or mesh is made for the altar — a latticework platform beneath the sacrificial fire. Bronze withstands heat (unlike gold or silver); the grating allows ash to fall while supporting the burning sacrifice above. The technical sophistication of this design — a suspended combustion platform — reflects that the revealed pattern encompasses engineering as well as theology.</p>",
"5": "<p>The bronze grating is placed under the <strong>karkov</strong> (<em>kar-KOV</em>): 'ledge/rim/shelf' (H3764 — a projecting shelf around the altar exterior). The grating is suspended at the midpoint of the altar — not at the top or bottom but in the middle. This arrangement creates a lower chamber (for ash collection) and an upper chamber (for the fire and sacrifice), with the grating as the dividing floor between them.</p>",
"6": "<p>Acacia wood poles (<em>baddei shittim</em>) overlaid with bronze for carrying the altar. The altar travels the same way as the ark and table — by poles through rings. But the altar's poles are bronze-clad (not gold), matching the outer court material system. Every object has poles; every sacred object is portable. The God of the desert tabernacle does not dwell in a fixed temple but travels with his pilgrim people.</p>",
"7": "<p>The poles are inserted through the rings on the sides of the altar for carrying. The spatial arrangement ensures that the altar can be lifted and carried without the bearers touching the sacrificial surface. The altar is carried by priests — the Kohathites are assigned the altar in Num 4:13-14. What has received the blood of sacrifice requires careful handling in transport.</p>",
"8": "<p><strong>nevuv luchot taa'aseh oto</strong> (<em>ne-VOOV loo-KHOT ta-ah-SEH oh-TO</em>): 'hollow with boards you shall make it' — the altar is hollow, constructed of bronze-overlaid boards, not solid. <strong>ka'asher her'ah otkha bahar ken ya'asu</strong>: 'as he showed you on the mountain, so they shall make it.' The <em>tabnit</em> principle again — the altar design, like every other element, is revealed, not invented. The hollow construction makes it portable (lighter than solid stone or metal) while maintaining the sacred form revealed on the mountain.</p>",
"9": "<p><strong>chatzer ha-mishkan</strong> (<em>khatz-AR hah-mish-KAN</em>): 'the courtyard of the tabernacle' (H2691, from <em>chatzar</em> — to enclose/surround; also a village settlement in the wilderness). The courtyard is the outermost sacred zone — still sacred, but open to all Israel (not just priests). The south side is 100 cubits long — fine twisted linen hangings (<em>qelai shesh moshzar</em>) creating a white linen enclosure that marks off the sacred precincts from the camp.</p>",
"10": "<p>Twenty pillars and twenty bronze sockets for the south side — one socket per pillar. <strong>vaveihem</strong> (<em>vah-VEI-hem</em>): 'their hooks' (H2053 — the letter <em>vav</em> itself means hook/nail, shaped like a hook). <strong>chashuqeihem</strong> (<em>kha-shoo-KEI-hem</em>): 'their bands/connecting rods' (H2838). Silver hooks and bands on the bronze-socketed pillars — silver connects the courtyard pillars to each other, creating a unified white linen enclosure. The courtyard is bounded by silver at the top of its pillars, bronze at the base.</p>",
"11": "<p>The north side exactly mirrors the south: 100 cubits of linen hangings, twenty bronze-socketed pillars, silver hooks and bands. The bilateral symmetry of the courtyard (north = south) reflects the divine orderliness that pervades the entire tabernacle design. What is said of one wall is equally true of the other — no hierarchy between the lateral approaches to the divine dwelling.</p>",
"12": "<p>The west end of the courtyard: 50 cubits wide, ten pillars with ten sockets. The courtyard is 100 cubits (east-west) by 50 cubits (north-south) — twice as long as it is wide. The proportional rectangle (2:1) mirrors the inner tabernacle structure, creating nested rectangular spaces of increasing holiness: outer courtyard (100×50), tabernacle itself (30×10), with the veil dividing the tabernacle into holy place (20×10) and holy of holies (10×10).</p>",
"13": "<p>The east side (<em>miqdma qedmah</em> — toward the east) is also 50 cubits wide — matching the west end. The gate will occupy 20 of these 50 cubits (v.16), with 15-cubit screens on each side. The eastern orientation of the entrance mirrors Eden (Gen 3:24) and Ezekiel's vision (Ezek 43:1-4) — in Israelite sacred architecture, one enters from the east and moves westward toward the divine presence.</p>",
"14": "<p>Fifteen cubits of linen hanging on one side of the gate, with three pillars and three sockets. The gate flanks create a framing for the entrance — the 20-cubit gate is proportionally centered within the 50-cubit east end, with 15 cubits of screening on each side. Approach to the divine dwelling is architecturally managed: the gate is wide (20 cubits) and well-lit (open to the east), but it is the only entry point.</p>",
"15": "<p>Fifteen cubits on the other side of the gate — three pillars and three sockets. The symmetrical flanking of the entrance creates a formal gateway. The tabernacle has one gate facing east — one entrance to the sacred precincts. Jesus applies this spatial theology in John 10:9: 'I am the gate; whoever enters through me will be saved.' The exclusive entrance of the divine dwelling becomes a Christological claim.</p>",
"16": "<p><strong>masak sha'ar hechatzar</strong> (<em>mah-SAK sha-AR heh-khatz-AR</em>): 'screen/curtain for the gate of the courtyard' (H4539 H8179 H2691). The gate screen is 20 cubits wide, in the same four colors as the tabernacle entrance (tekhelet/argaman/shani/shesh) but with <em>ma'aseh roqem</em> (embroiderer's work H4639 H7551) rather than the most skilled weaving. Four pillars and four sockets for the 20-cubit gate. The outer gate is decorated but less elaborately than the inner — holiness increases as one moves inward.</p>",
"17": "<p><strong>kol ammudei hechatzar saviv meshhuqqim kesef</strong>: 'all the pillars of the courtyard all around with silver bands' — <strong>meshhuqqim</strong> (H2838 — banded/joined with silver). The courtyard pillars, regardless of which side, all share silver connecting rods and hooks. Silver unifies the entire courtyard at the top; bronze grounds every pillar at the bottom. The courtyard is literally ringed with silver — the redemption metal (cf. Ex 30:11-16 — silver as the ransom price of the census).</p>",
"18": "<p>The full dimensions of the courtyard: <strong>orech hechatzar meah ba'amma uerochav chamishim bachameshin</strong> — length 100 cubits, width 50 cubits, height 5 cubits of twisted linen hangings. The courtyard height (5 cubits, ca. 2.3m) creates a privacy/separation zone without being so tall as to be oppressive — enough to mark off the sacred from the common while allowing air and light. The bronze sockets run beneath the entire perimeter.</p>",
"19": "<p><strong>kol kelei ha-mishkan bechol avodato</strong>: 'all the vessels/equipment of the tabernacle for all its service' — including all <strong>yetedotav</strong> (<em>ye-teh-do-TAV</em>): 'its tent pegs/stakes' (H3489). Even the tent pegs — the simplest, most utilitarian objects — are listed among the sacred equipment. Every peg that anchors the tabernacle to the Sinai desert is <em>nechoshet</em> (bronze), part of the consecrated complex. Nothing about the tabernacle is secular, not even the hardware buried in the ground.</p>",
"20": "<p><strong>shemen zayit zakh katit lammaor</strong> (<em>sheh-MEN zay-IT zakh kah-TEET lah-mah-OR</em>): 'pure beaten olive oil for the light' (H8081 H2132 H2134 H3795 H3974). <strong>Katit</strong> (H3795) means beaten/crushed — the oil is produced by pounding the olives, not pressing them under a stone. The finest grade of oil, from gently beaten olives. The word for olive press is <em>gat shemen</em> — precisely Gethsemane. The oil that feeds the eternal lamp is <em>katit</em>, crushed oil, from the garden whose name means crushing. <strong>ner tamid</strong> (<em>NER tah-MEED</em>): 'perpetual/continual lamp' (H5216 H8548). The lamp must not go out — it burns through the night before YHWH, the undying light of the covenant.</p>",
"21": "<p><strong>me'erev ad boqer</strong> (<em>me-EH-rev ad BO-ker</em>): 'from evening until morning' — the lamp burns through the night, the hours when darkness rules outside. Aaron and his sons tend the <em>ner tamid</em> in the tent of meeting before YHWH. <strong>chukkat olam ledorotam</strong> (<em>khuk-KAT oh-LAM le-doh-roh-TAM</em>): 'a perpetual statute throughout their generations' (H2708 H5769). The lampstand service is not temporary legislation but <em>olam</em> — the same word for the everlasting covenant. <strong>me'et benei Yisrael</strong>: the oil comes from Israel, supplied by the people, tended by the priests — the whole nation sustains the light that burns before the divine presence on their behalf.</p>"
}
}

def main():
    data = load_comm('mkt-original', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-original', 'exodus', data)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'exodus.json'))
    all_ok = True
    for ch in ['25', '26', '27']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(data.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
